Object.assign(controls, {
  charSet: 'numbers',
  charCount: 520,
  rotationSpeed: 0.0012,
  charSize: 0.42,
  glowColor: '#7d2a1f',
  autoRotate: true,
  ...controls,
});

const scene = new THREE.Scene();
scene.background = null;

const camera = new THREE.PerspectiveCamera(55, window.innerWidth / window.innerHeight, 0.1, 1000);
camera.position.z = 7.2;

const renderer = new THREE.WebGLRenderer({ antialias: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
document.body.appendChild(renderer.domElement);

const charSets = {
  numbers:     '0123456789',
  letters:     'ABCDEFGHIJKLMNOPQRSTUVWXYZ',
  binary:      '01',
  hexadecimal: '0123456789ABCDEF',
  matrix:      'ｦｧｩｪｫｬｭｮｯｱｲｳｴｵｶｷｸｺｻｼｽｿﾀﾁﾂﾃﾅﾆﾇﾉﾊﾋﾌﾍﾎﾏﾐﾑﾒﾓﾔﾕﾖﾗﾘﾙﾚﾛﾜﾝ',
  symbols:     '@#$%&*!?+=~<>{}[]',
  custom:      'AUDITUS·CUSTODIA·MANDATUM·LEDGER·PROBATIO·SIGILLUM·QUAESTOR·IMPERIUM·SCRIPTUM·VERITAS·CATENA·OBSERVO',
};

// Custom character input overlay
const customInput = document.createElement('input');
customInput.type = 'text';
customInput.value = 'AUDITUS·CUSTODIA·MANDATUM·LEDGER·PROBATIO·SIGILLUM·QUAESTOR·IMPERIUM·SCRIPTUM·VERITAS·CATENA·OBSERVO';
customInput.placeholder = 'Type your characters…';
Object.assign(customInput.style, {
  position: 'fixed',
  bottom: '72px',
  left: '50%',
  transform: 'translateX(-50%)',
  background: 'rgba(0,0,0,0.75)',
  color: '#fff',
  border: '1px solid rgba(255,255,255,0.35)',
  borderRadius: '8px',
  padding: '9px 18px',
  fontSize: '20px',
  letterSpacing: '5px',
  outline: 'none',
  display: 'none',
  zIndex: '1000',
  minWidth: '280px',
  textAlign: 'center',
  fontFamily: 'monospace',
  boxShadow: '0 0 18px rgba(255,255,255,0.1)',
});
document.body.appendChild(customInput);
_cleanup.signal.addEventListener('abort', () => customInput.remove());

function createCharTexture(char, color) {
  const canvas = document.createElement('canvas');
  canvas.width = 64;
  canvas.height = 64;
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, 64, 64);
  ctx.fillStyle = color;
  ctx.font = 'bold 44px monospace';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(char, 32, 32);
  return new THREE.CanvasTexture(canvas);
}

function fibonacciSphere(samples, radius) {
  const pts = [];
  const goldenAngle = Math.PI * (3 - Math.sqrt(5));
  for (let i = 0; i < samples; i++) {
    const y = 1 - (i / (samples - 1)) * 2;
    const r = Math.sqrt(1 - y * y);
    const theta = goldenAngle * i;
    pts.push(new THREE.Vector3(Math.cos(theta) * r * radius, y * radius, Math.sin(theta) * r * radius));
  }
  return pts;
}

const SPHERE_RADIUS = 3;
const sphereGroup = new THREE.Group();
scene.add(sphereGroup);

let lastCharSet = '';
let lastCount = 0;
let lastColor = '';
let lastCustomChars = '';
const _wp = new THREE.Vector3();

function getActiveChars() {
  if (controls.charSet === 'custom') {
    return customInput.value.trim() || '?';
  }
  return charSets[controls.charSet] || charSets.numbers;
}

function buildSphere() {
  sphereGroup.children.slice().forEach(child => {
    child.material.map.dispose();
    child.material.dispose();
    sphereGroup.remove(child);
  });

  const chars = getActiveChars();
  const points = fibonacciSphere(controls.charCount, SPHERE_RADIUS);

  points.forEach(pos => {
    const char = chars[Math.floor(Math.random() * chars.length)];
    const tex = createCharTexture(char, controls.glowColor);
    const mat = new THREE.SpriteMaterial({ map: tex, transparent: true, depthWrite: false });
    const sprite = new THREE.Sprite(mat);
    sprite.position.copy(pos);
    const depth = (pos.z / SPHERE_RADIUS + 1) * 0.5;
    sprite.scale.setScalar(controls.charSize * (0.62 + depth * 1.6) * 3.2);
    sprite.material.opacity = 0.55 + depth * 0.45;
    sphereGroup.add(sprite);
  });

  lastCharSet = controls.charSet;
  lastCount = controls.charCount;
  lastColor = controls.glowColor;
  lastCustomChars = customInput.value;
}

buildSphere();

let isDragging = false;
let prevMouse = { x: 0, y: 0 };
let velX = 0, velY = 0;

renderer.domElement.addEventListener('mousedown', e => {
  isDragging = true;
  prevMouse = { x: e.clientX, y: e.clientY };
  velX = velY = 0;
}, { signal: _cleanup.signal });

window.addEventListener('mousemove', e => {
  if (!isDragging) return;
  const dx = e.clientX - prevMouse.x;
  const dy = e.clientY - prevMouse.y;
  velY = dx * 0.008;
  velX = dy * 0.008;
  sphereGroup.rotation.y += velY;
  sphereGroup.rotation.x += velX;
  prevMouse = { x: e.clientX, y: e.clientY };
}, { signal: _cleanup.signal });

window.addEventListener('mouseup', () => { isDragging = false; }, { signal: _cleanup.signal });

function animate() {
  requestAnimationFrame(animate);

  // Show / hide custom input
  customInput.style.display = controls.charSet === 'custom' ? 'block' : 'none';

  const customCharsChanged = controls.charSet === 'custom' && customInput.value !== lastCustomChars;

  if (
    controls.charSet !== lastCharSet ||
    controls.charCount !== lastCount ||
    controls.glowColor !== lastColor ||
    customCharsChanged
  ) {
    buildSphere();
  }

  if (controls.autoRotate && !isDragging) {
    sphereGroup.rotation.y += controls.rotationSpeed;
    sphereGroup.rotation.x += controls.rotationSpeed * 0.25;
  } else if (!isDragging) {
    velX *= 0.96;
    velY *= 0.96;
    sphereGroup.rotation.x += velX;
    sphereGroup.rotation.y += velY;
  }

  const baseSize = controls.charSize;
  sphereGroup.children.forEach(sprite => {
    sprite.getWorldPosition(_wp);
    const depth = (_wp.z / SPHERE_RADIUS + 1) * 0.5;
    sprite.scale.setScalar(baseSize * (0.62 + depth * 1.6) * 3.2);
    sprite.material.opacity = 0.55 + depth * 0.45;
  });

  renderer.render(scene, camera);
}

window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
}, { signal: _cleanup.signal });

animate();
